function esc(value) {
  return String(value || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function titleFromSlug(slug) {
  const upper = { gst: 'GST', itr: 'ITR', huf: 'HUF', tds: 'TDS', hsn: 'HSN', sac: 'SAC', itc: 'ITC', isd: 'ISD', rcm: 'RCM', lut: 'LUT', cfo: 'CFO', react: 'React', nodejs: 'Node.js', python: 'Python', esop: 'ESOP', pan: 'PAN', aadhaar: 'Aadhaar', roc: 'ROC', mca: 'MCA', ai: 'AI', ml: 'ML' };
  return slug.split('-').map(part => upper[part] || part.charAt(0).toUpperCase() + part.slice(1)).join(' ');
}

function list(items) {
  return `<ul class="wi-detail-list">${items.map(item => `<li>${item}</li>`).join('')}</ul>`;
}

function steps(items) {
  return `<div class="lp-steps">${items.map(step => `<div class="lp-step"><h3>${esc(step.title)}</h3><p>${step.body}</p></div>`).join('')}</div>`;
}

function table(headers, rows) {
  return `<table class="wi-table"><thead><tr>${headers.map(h => `<th>${esc(h)}</th>`).join('')}</tr></thead><tbody>${rows.map(row => `<tr>${row.map(cell => `<td>${cell}</td>`).join('')}</tr>`).join('')}</tbody></table>`;
}

function linkList(slugs) {
  return slugs.map(slug => `<a href="/seo-pages/${slug}.html">${esc(titleFromSlug(slug))}</a>`).join('');
}

